const meta = $('🧩 Siapkan Payload Gemini').first().json;
const response = $input.first().json;

function stripCodeFence(value) {
  return String(value || '')
    .replace(/^\s*\`\`\`(?:json)?\s*/i, '')
    .replace(/\s*\`\`\`\s*$/i, '')
    .trim();
}

function objectLikeText(value) {
  const cleaned = stripCodeFence(value);
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    return cleaned.slice(firstBrace, lastBrace + 1);
  }
  return cleaned;
}

function extractLooseField(source, key) {
  const keys = ['image_summary_id', 'user_intent_id', 'veo_prompt_en', 'negative_prompt_en', 'telegram_caption_id', 'prompt'];
  const nextKeys = keys.filter((candidate) => candidate !== key).join('|');
  const pattern = new RegExp('"' + key + '"\\s*:\\s*([\\s\\S]*?)(?=,\\s*"(' + nextKeys + ')"\\s*:|\\n?\\s*}\\s*$)', 'i');
  const match = source.match(pattern);
  if (!match) return '';
  let value = match[1].trim().replace(/,$/, '').trim();
  if (value.startsWith('"')) value = value.slice(1);
  if (value.endsWith('"')) value = value.slice(0, -1);
  return value
    .replace(/\\n/g, ' ')
    .replace(/\\r/g, ' ')
    .replace(/\\t/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseGeminiOutput(text) {
  const candidate = objectLikeText(text);
  try {
    return JSON.parse(candidate);
  } catch (jsonError) {
    const loose = {
      image_summary_id: extractLooseField(candidate, 'image_summary_id'),
      user_intent_id: extractLooseField(candidate, 'user_intent_id'),
      veo_prompt_en: extractLooseField(candidate, 'veo_prompt_en') || extractLooseField(candidate, 'prompt'),
      negative_prompt_en: extractLooseField(candidate, 'negative_prompt_en'),
      telegram_caption_id: extractLooseField(candidate, 'telegram_caption_id'),
      _parseWarning: jsonError.message,
    };
    if (loose.veo_prompt_en) return loose;
    return {
      veo_prompt_en: stripCodeFence(text),
      negative_prompt_en: '',
      telegram_caption_id: 'Video selesai dibuat dari gambar Telegram.',
      _parseWarning: jsonError.message,
    };
  }
}

try {
  if (response.error) throw new Error(response.error.message || JSON.stringify(response.error));
  const parts = response.candidates?.[0]?.content?.parts || [];
  const text = parts.map((part) => part.text || '').join('\n').trim();
  if (!text) throw new Error('Response Gemini kosong atau tidak memiliki candidates[0].content.parts[].text.');

  const parsed = parseGeminiOutput(text);
  const veoPrompt = String(parsed.veo_prompt_en || parsed.prompt || '').trim();
  if (!veoPrompt) throw new Error('Output Gemini tidak memiliki field veo_prompt_en.');

  return [{
    json: {
      ...meta,
      imageSummaryId: parsed.image_summary_id || '',
      userIntentId: parsed.user_intent_id || '',
      veoPrompt,
      negativePrompt: String(parsed.negative_prompt_en || 'blurry, distorted, low quality, broken text, extra limbs').trim(),
      telegramCaption: String(parsed.telegram_caption_id || 'Video selesai dibuat dari gambar Telegram.').trim(),
      geminiRawText: text,
      parseWarning: parsed._parseWarning || '',
    },
  }];
} catch (error) {
  return [{
    json: {
      ...meta,
      hasError: true,
      failedNode: '📝 Parse Prompt Veo',
      errorMessage: error.message,
      rawGeminiResponse: JSON.stringify(response).slice(0, 3000),
    },
  }];
}

