const item = $input.first().json;

function sanitizePrompt(value) {
  let prompt = String(value || '').trim();
  const replacements = [
    [/\b(blood|bloody|gore|gory|corpse|dead body|decapitat\w*|dismember\w*)\b/gi, 'red visual detail'],
    [/\b(kill|killing|murder|suicide|self[- ]?harm|harmful injury|stab\w*|shoot\w*)\b/gi, 'dramatic tension'],
    [/\b(gun|rifle|pistol|knife|blade|weapon|bomb|explosive|explosion)\b/gi, 'neutral prop'],
    [/\b(nude|naked|sex|sexual|erotic|fetish|porn\w*)\b/gi, 'tasteful lifestyle'],
    [/\b(child|children|kid|minor|underage)\b/gi, 'person'],
    [/\b(drug|cocaine|heroin|meth|marijuana|weed|narcotic)\b/gi, 'wellness product'],
    [/\b(hate|racist|slur|terrorist|extremist)\b/gi, 'neutral social context'],
  ];
  for (const [pattern, replacement] of replacements) {
    prompt = prompt.replace(pattern, replacement);
  }
  prompt = prompt
    .replace(/\s+/g, ' ')
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .trim();

  const safetyPrefix = 'Safe, policy-compliant cinematic product/lifestyle video. No violence, no gore, no explicit sexual content, no minors, no weapons, no illegal activity, no hate symbols.';
  return (safetyPrefix + ' ' + prompt).slice(0, 3000);
}

const safePrompt = sanitizePrompt(item.veoPrompt);
const safeNegative = [
  item.negativePrompt || '',
  'violence, gore, blood, weapons, explicit sexual content, nudity, minors, illegal drugs, hate symbols, self harm, realistic injury, disturbing content',
].filter(Boolean).join(', ');

return [{
  json: {
    ...item,
    veoPromptOriginal: item.veoPrompt,
    veoPrompt: safePrompt,
    negativePrompt: safeNegative,
    safetySanitized: safePrompt !== item.veoPrompt,
    safetyRetryCount: item.safetyRetryCount || 0,
  },
}];

const item = $input.first().json;

function compact(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function removeSensitiveLanguage(value) {
  let prompt = compact(value);
  const replacements = [
    [/\b(blood|bloody|gore|gory|corpse|dead body|decapitat\w*|dismember\w*)\b/gi, 'clean visual detail'],
    [/\b(kill|killing|murder|suicide|self[- ]?harm|harmful injury|stab\w*|shoot\w*)\b/gi, 'dramatic but harmless moment'],
    [/\b(gun|rifle|pistol|knife|blade|weapon|bomb|explosive|explosion)\b/gi, 'safe neutral prop'],
    [/\b(nude|naked|sex|sexual|erotic|fetish|porn\w*)\b/gi, 'tasteful lifestyle tone'],
    [/\b(child|children|kid|minor|underage)\b/gi, 'adult person'],
    [/\b(drug|cocaine|heroin|meth|marijuana|weed|narcotic)\b/gi, 'neutral product'],
    [/\b(hate|racist|slur|terrorist|extremist)\b/gi, 'neutral background'],
  ];
  for (const [pattern, replacement] of replacements) prompt = prompt.replace(pattern, replacement);
  return prompt;
}

const sourcePrompt = item.veoPromptOriginal || item.veoPrompt;
const safePrompt = removeSensitiveLanguage(sourcePrompt);
const rewrittenPrompt = [
  'Safe commercial cinematic video, family-friendly, policy-compliant, non-violent, no explicit or harmful content.',
  safePrompt,
  'Use gentle camera movement, tasteful lighting, realistic product-focused motion, upbeat visual tone.',
].join(' ').slice(0, 2800);

return [{
  json: {
    ...item,
    hasError: false,
    errorMessage: '',
    failedNode: '',
    veoPrompt: rewrittenPrompt,
    negativePrompt: 'violence, gore, blood, weapons, explicit sexual content, nudity, minors, illegal drugs, hate symbols, self harm, realistic injury, disturbing content',
    safetyRetryCount: Number(item.safetyRetryCount || 0) + 1,
    safetyRewriteReason: item.errorMessage || 'Sensitive prompt retry',
  },
}];
